package org.apache.commons.csv;

import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.UNDEFINED;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.apache.commons.csv.Lexer;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.ExtendedBufferedReader;
import org.apache.commons.csv.Token;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class LexerIsStartOfLineTest {

    private Lexer lexer;

    @BeforeEach
    void setUp() {
        CSVFormat format = Mockito.mock(CSVFormat.class);
        ExtendedBufferedReader in = Mockito.mock(ExtendedBufferedReader.class);
        // Create an anonymous subclass of Lexer since Lexer is abstract
        lexer = new Lexer(format, in) {
            @Override
            Token nextToken(Token reusableToken) {
                return null;
            }
        };
    }

    @Test
    void testIsStartOfLine_LF_ReturnsTrue() {
        assertTrue(lexer.isStartOfLine(LF));
    }

    @Test
    void testIsStartOfLine_CR_ReturnsTrue() {
        assertTrue(lexer.isStartOfLine(CR));
    }

    @Test
    void testIsStartOfLine_UNDEFINED_ReturnsTrue() {
        assertTrue(lexer.isStartOfLine(UNDEFINED));
    }

    @Test
    void testIsStartOfLine_OtherChar_ReturnsFalse() {
        assertFalse(lexer.isStartOfLine('a'));
        assertFalse(lexer.isStartOfLine(0));
        assertFalse(lexer.isStartOfLine(32)); // space
        assertFalse(lexer.isStartOfLine(255));
    }
}
